namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications = new List<Notification>
        {
            new(1, "Welcome to the notification centre!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-20)),
            new(3, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-10)),
        };
        _nextId = 4;
    }

    /// <summary>Returns all notifications available right now.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        // Simulate a new notification arriving roughly every 15 seconds.
        MaybeGenerateFake();

        lock (_notifications)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Timestamp > since).ToList());
        }
    }

    private void MaybeGenerateFake()
    {
        lock (_notifications)
        {
            var last = _notifications.MaxBy(n => n.Timestamp);
            if (last is not null && DateTime.UtcNow - last.Timestamp > TimeSpan.FromSeconds(15))
            {
                var id = _nextId++;
                _notifications.Add(new Notification(
                    id,
                    $"Auto-generated notification #{id}",
                    DateTime.UtcNow));
            }
        }
    }
}

