@page "/notifications"
@using NotificationsApp.Services
@rendermode InteractiveServer
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    // Runs during SSR *and* when the component re-initialises interactively.
    // Because we use PersistentComponentState the data loaded in SSR is reused —
    // no second service call when the page becomes interactive.
    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        _persistSub = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<List<Notification>>("notifs", out var restored))
        {
            // Interactive re-init: reuse the SSR data.
            _notifications = restored!;
        }
        else
        {
            // SSR (first render): load from the service.
            _notifications = await NotificationSvc.GetNotificationsAsync();
        }

        _lastCheck = _notifications.Count > 0
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("notifs", _notifications);
        return Task.CompletedTask;
    }

    // OnAfterRenderAsync is only called on the client (interactive) — never during SSR.
    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
        return Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newer = await NotificationSvc.GetNotificationsSinceAsync(_lastCheck);
                if (newer.Count > 0)
                {
                    _notifications.AddRange(newer);
                    _lastCheck = newer.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _persistSub.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

